-- FineType Profile Evaluation Pipeline
-- =============================================================================
-- Compares finetype profile predictions against ground truth annotations using
-- the schema mapping (eval/schema_mapping.csv). Produces per-type accuracy
-- metrics, confusion matrix, and actionable misclassification list.
--
-- Usage:
--   duckdb < eval/eval_profile.sql
--
-- Prerequisites:
--   1. Profile results:  eval/eval_output/profile_results.csv
--      (generated by eval/profile_eval.sh)
--   2. Ground truth:     eval/eval_output/ground_truth.csv
--      (generated by eval/profile_eval.sh)
--   3. Schema mapping:   eval/schema_mapping.csv
--
-- Or via Makefile:
--   make eval-profile       # runs the full pipeline

.mode box
.timer on

-- ═══════════════════════════════════════════════════════════════════════════════
-- 1. LOAD DATA
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          LOADING DATA                                            '
.print '═══════════════════════════════════════════════════════════════════'

-- Schema mapping (from NNFT-079)
CREATE OR REPLACE TABLE schema_mapping AS
SELECT * FROM read_csv('eval/schema_mapping.csv', auto_detect=true);

.print ''
.print '--- Schema mapping loaded ---'
SELECT
    count(*) AS total_mappings,
    count(*) FILTER (match_quality = 'direct') AS direct,
    count(*) FILTER (match_quality = 'close') AS close,
    count(*) FILTER (match_quality = 'partial') AS partial,
    count(*) FILTER (match_quality = 'semantic_only') AS semantic_only
FROM schema_mapping;

-- Profile results: dataset, column_name, predicted_type, confidence
CREATE OR REPLACE TABLE profile_results AS
SELECT * FROM read_csv('eval/eval_output/profile_results.csv', auto_detect=true);

.print ''
.print '--- Profile results loaded ---'
SELECT
    count(*) AS total_columns,
    count(DISTINCT dataset) AS datasets,
    count(DISTINCT predicted_type) AS unique_predictions,
    ROUND(avg(confidence), 3) AS avg_confidence
FROM profile_results;

-- Ground truth: dataset, column_name, gt_label
CREATE OR REPLACE TABLE ground_truth AS
SELECT * FROM read_csv('eval/eval_output/ground_truth.csv', auto_detect=true);

.print ''
.print '--- Ground truth loaded ---'
SELECT
    count(*) AS total_annotations,
    count(DISTINCT dataset) AS datasets,
    count(DISTINCT gt_label) AS unique_gt_labels
FROM ground_truth;

-- ═══════════════════════════════════════════════════════════════════════════════
-- 2. JOIN PREDICTIONS ↔ GROUND TRUTH ↔ MAPPING
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          JOINING PREDICTIONS WITH GROUND TRUTH                   '
.print '═══════════════════════════════════════════════════════════════════'

CREATE OR REPLACE TABLE eval_joined AS
SELECT
    pr.dataset,
    pr.column_name,
    pr.predicted_type,
    pr.confidence,
    gt.gt_label,
    sm.finetype_label AS expected_ft_label,
    sm.finetype_domain AS expected_ft_domain,
    sm.match_quality,
    sm.expand AS expansion_candidate,
    split_part(pr.predicted_type, '.', 1) AS predicted_domain,
    -- Scoring: label-level match
    CASE
        WHEN sm.finetype_label IS NOT NULL AND sm.finetype_label != ''
             AND pr.predicted_type = sm.finetype_label
        THEN true
        -- Boolean sub-types are interchangeable: binary/terms/initials all satisfy
        -- a generic "boolean" GT label (the GT doesn't distinguish sub-types)
        WHEN sm.finetype_label LIKE 'representation.boolean.%'
             AND pr.predicted_type LIKE 'representation.boolean.%'
        THEN true
        -- Time sub-types are interchangeable: hm_24h ≈ hms_24h (GT "time 24h"
        -- doesn't distinguish whether seconds are present)
        WHEN sm.finetype_label LIKE 'datetime.time.%'
             AND pr.predicted_type LIKE 'datetime.time.%'
        THEN true
        -- Geographic hierarchy: continent ≈ region ≈ state are interchangeable
        -- (GT "region" covers continent-level through state-level subdivisions)
        WHEN sm.finetype_label IN (
                 'geography.location.region',
                 'geography.location.state',
                 'geography.location.continent'
             )
             AND pr.predicted_type IN (
                 'geography.location.region',
                 'geography.location.state',
                 'geography.location.continent'
             )
        THEN true
        -- Timestamp sub-types are interchangeable: iso_8601 ≈ iso_8601_microseconds
        -- (GT "timestamp" doesn't distinguish microsecond precision)
        WHEN sm.finetype_label LIKE 'datetime.timestamp.%'
             AND pr.predicted_type LIKE 'datetime.timestamp.%'
        THEN true
        ELSE false
    END AS label_match,
    -- Scoring: domain-level match
    CASE
        WHEN sm.finetype_domain IS NOT NULL AND sm.finetype_domain != ''
             AND split_part(pr.predicted_type, '.', 1) = sm.finetype_domain
        THEN true
        ELSE false
    END AS domain_match,
    -- Is this a type FineType should be able to detect?
    CASE
        WHEN sm.match_quality IN ('direct', 'close') THEN 'format_detectable'
        WHEN sm.match_quality = 'partial' THEN 'partially_detectable'
        WHEN sm.match_quality = 'semantic_only' THEN 'semantic_only'
        ELSE 'unmapped'
    END AS detectability
FROM profile_results pr
LEFT JOIN ground_truth gt
    ON pr.dataset = gt.dataset AND pr.column_name = gt.column_name
LEFT JOIN schema_mapping sm
    ON gt.gt_label = sm.gt_label;

SELECT
    count(*) AS total_joined,
    count(*) FILTER (gt_label IS NOT NULL) AS with_gt,
    count(*) FILTER (gt_label IS NULL) AS no_gt,
    count(*) FILTER (match_quality IS NOT NULL) AS mapped,
    count(*) FILTER (match_quality IS NULL AND gt_label IS NOT NULL) AS gt_not_in_mapping
FROM eval_joined;

-- ═══════════════════════════════════════════════════════════════════════════════
-- 3. OVERALL ACCURACY
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          OVERALL ACCURACY                                        '
.print '═══════════════════════════════════════════════════════════════════'

-- 3a. Overall accuracy by detectability tier
.print ''
.print '--- Accuracy by detectability tier ---'
SELECT
    detectability,
    count(*) AS columns,
    sum(CASE WHEN label_match THEN 1 ELSE 0 END) AS label_correct,
    ROUND(sum(CASE WHEN label_match THEN 1 ELSE 0 END) * 100.0 / count(*), 1) AS label_accuracy_pct,
    sum(CASE WHEN domain_match THEN 1 ELSE 0 END) AS domain_correct,
    ROUND(sum(CASE WHEN domain_match THEN 1 ELSE 0 END) * 100.0 / count(*), 1) AS domain_accuracy_pct
FROM eval_joined
WHERE gt_label IS NOT NULL AND match_quality IS NOT NULL
GROUP BY detectability
ORDER BY
    CASE detectability
        WHEN 'format_detectable' THEN 1
        WHEN 'partially_detectable' THEN 2
        WHEN 'semantic_only' THEN 3
        ELSE 4
    END;

-- 3b. Headline number: format-detectable types only
.print ''
.print '--- Headline accuracy (format-detectable types only) ---'
SELECT
    'Format-detectable (direct + close)' AS metric,
    count(*) AS columns,
    sum(CASE WHEN label_match THEN 1 ELSE 0 END) AS label_correct,
    ROUND(sum(CASE WHEN label_match THEN 1 ELSE 0 END) * 100.0 / NULLIF(count(*), 0), 1) AS label_accuracy_pct,
    sum(CASE WHEN domain_match THEN 1 ELSE 0 END) AS domain_correct,
    ROUND(sum(CASE WHEN domain_match THEN 1 ELSE 0 END) * 100.0 / NULLIF(count(*), 0), 1) AS domain_accuracy_pct
FROM eval_joined
WHERE detectability = 'format_detectable';

-- ═══════════════════════════════════════════════════════════════════════════════
-- 4. PER-TYPE METRICS (Precision, Recall, F1)
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          PER-TYPE METRICS                                        '
.print '═══════════════════════════════════════════════════════════════════'

-- 4a. Per GT label: how well does FineType predict each ground truth type?
.print ''
.print '--- Per GT label accuracy (format-detectable + partial only) ---'
SELECT
    ej.gt_label,
    ej.match_quality,
    ej.expected_ft_label,
    count(*) AS total,
    sum(CASE WHEN ej.label_match THEN 1 ELSE 0 END) AS label_correct,
    ROUND(sum(CASE WHEN ej.label_match THEN 1 ELSE 0 END) * 100.0 / count(*), 1) AS label_recall_pct,
    sum(CASE WHEN ej.domain_match THEN 1 ELSE 0 END) AS domain_correct,
    ROUND(sum(CASE WHEN ej.domain_match THEN 1 ELSE 0 END) * 100.0 / count(*), 1) AS domain_recall_pct,
    ROUND(avg(ej.confidence), 3) AS avg_confidence
FROM eval_joined ej
WHERE ej.match_quality IN ('direct', 'close', 'partial')
GROUP BY ej.gt_label, ej.match_quality, ej.expected_ft_label
HAVING count(*) >= 1
ORDER BY total DESC;

-- 4b. Per predicted type: precision (how often is this prediction correct?)
.print ''
.print '--- Per predicted type precision (against mapped GT) ---'
WITH predictions AS (
    SELECT
        predicted_type,
        count(*) AS times_predicted,
        sum(CASE WHEN label_match THEN 1 ELSE 0 END) AS label_correct,
        sum(CASE WHEN domain_match THEN 1 ELSE 0 END) AS domain_correct
    FROM eval_joined
    WHERE gt_label IS NOT NULL AND match_quality IN ('direct', 'close', 'partial')
    GROUP BY predicted_type
)
SELECT
    predicted_type,
    times_predicted,
    label_correct,
    ROUND(label_correct * 100.0 / times_predicted, 1) AS label_precision_pct,
    domain_correct,
    ROUND(domain_correct * 100.0 / times_predicted, 1) AS domain_precision_pct
FROM predictions
WHERE times_predicted >= 2
ORDER BY times_predicted DESC;

-- ═══════════════════════════════════════════════════════════════════════════════
-- 5. MODEL ERRORS vs SEMANTIC GAPS
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          MODEL ERRORS vs SEMANTIC GAPS                           '
.print '═══════════════════════════════════════════════════════════════════'

-- 5a. Model errors: FineType SHOULD detect but got wrong
.print ''
.print '--- Model errors (format-detectable, wrong prediction) ---'
SELECT
    dataset,
    column_name,
    gt_label,
    expected_ft_label,
    predicted_type,
    match_quality,
    ROUND(confidence, 3) AS confidence
FROM eval_joined
WHERE detectability = 'format_detectable'
  AND NOT label_match
ORDER BY match_quality, gt_label, dataset;

-- 5b. Partial detection misses
.print ''
.print '--- Partial detection misses (could detect, did not match) ---'
SELECT
    gt_label,
    predicted_type,
    count(*) AS occurrences,
    ROUND(avg(confidence), 3) AS avg_confidence
FROM eval_joined
WHERE detectability = 'partially_detectable'
  AND NOT label_match
  AND NOT domain_match
GROUP BY gt_label, predicted_type
ORDER BY occurrences DESC
LIMIT 30;

-- 5c. Semantic gaps: correctly identified as NOT the user's expectation
.print ''
.print '--- Semantic gap summary (FineType cannot detect these by design) ---'
SELECT
    gt_label,
    count(*) AS columns,
    list(DISTINCT predicted_type ORDER BY predicted_type) AS ft_predictions,
    ROUND(avg(confidence), 3) AS avg_confidence
FROM eval_joined
WHERE detectability = 'semantic_only'
GROUP BY gt_label
HAVING count(*) >= 2
ORDER BY columns DESC
LIMIT 20;

-- ═══════════════════════════════════════════════════════════════════════════════
-- 6. CONFUSION MATRIX (for format-detectable types)
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          CONFUSION MATRIX (Format-Detectable Types)              '
.print '═══════════════════════════════════════════════════════════════════'

.print ''
.print '--- GT label × predicted type (format-detectable only) ---'
SELECT
    gt_label AS gt,
    predicted_type AS predicted,
    count(*) AS n,
    CASE WHEN label_match THEN 'CORRECT' ELSE 'WRONG' END AS verdict
FROM eval_joined
WHERE detectability IN ('format_detectable', 'partially_detectable')
GROUP BY gt_label, predicted_type, label_match
HAVING count(*) >= 1
ORDER BY gt_label, n DESC;

-- ═══════════════════════════════════════════════════════════════════════════════
-- 7. ACTIONABLE MISCLASSIFICATIONS
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          ACTIONABLE MISCLASSIFICATIONS                           '
.print '═══════════════════════════════════════════════════════════════════'

-- The most impactful errors to fix (format-detectable, grouped by pattern)
.print ''
.print '--- Top misclassification patterns (what to fix next) ---'
SELECT
    gt_label,
    expected_ft_label,
    predicted_type AS actual_prediction,
    match_quality,
    count(*) AS occurrences,
    ROUND(avg(confidence), 3) AS avg_conf,
    list(DISTINCT dataset ORDER BY dataset)[:3] AS example_datasets
FROM eval_joined
WHERE NOT label_match
  AND match_quality IN ('direct', 'close', 'partial')
  AND expected_ft_label IS NOT NULL
  AND expected_ft_label != ''
GROUP BY gt_label, expected_ft_label, predicted_type, match_quality
ORDER BY occurrences DESC
LIMIT 20;

-- ═══════════════════════════════════════════════════════════════════════════════
-- 8. EXPANSION OPPORTUNITIES
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          TAXONOMY EXPANSION OPPORTUNITIES                        '
.print '═══════════════════════════════════════════════════════════════════'

.print ''
.print '--- GT labels flagged for expansion (from schema_mapping) ---'
SELECT
    sm.gt_label,
    count(ej.column_name) AS columns_in_eval,
    list(DISTINCT ej.predicted_type ORDER BY ej.predicted_type)[:5] AS current_predictions,
    ROUND(avg(ej.confidence), 3) AS avg_confidence
FROM schema_mapping sm
LEFT JOIN eval_joined ej ON sm.gt_label = ej.gt_label
WHERE sm.expand = 'true'
GROUP BY sm.gt_label
ORDER BY columns_in_eval DESC;

-- ═══════════════════════════════════════════════════════════════════════════════
-- 9. PER-DATASET SUMMARY
-- ═══════════════════════════════════════════════════════════════════════════════

.print ''
.print '═══════════════════════════════════════════════════════════════════'
.print '          PER-DATASET SUMMARY                                     '
.print '═══════════════════════════════════════════════════════════════════'

.print ''
.print '--- Per dataset accuracy ---'
SELECT
    dataset,
    count(*) AS columns,
    count(*) FILTER (gt_label IS NOT NULL) AS annotated,
    count(*) FILTER (detectability = 'format_detectable') AS fmt_detectable,
    sum(CASE WHEN detectability = 'format_detectable' AND label_match THEN 1 ELSE 0 END) AS fmt_label_correct,
    sum(CASE WHEN domain_match THEN 1 ELSE 0 END) AS domain_correct,
    ROUND(
        sum(CASE WHEN detectability = 'format_detectable' AND label_match THEN 1 ELSE 0 END) * 100.0 /
        NULLIF(count(*) FILTER (detectability = 'format_detectable'), 0), 1
    ) AS fmt_label_accuracy_pct,
    ROUND(
        sum(CASE WHEN domain_match THEN 1 ELSE 0 END) * 100.0 /
        NULLIF(count(*) FILTER (gt_label IS NOT NULL AND match_quality IS NOT NULL), 0), 1
    ) AS domain_accuracy_pct,
    ROUND(avg(confidence), 3) AS avg_confidence
FROM eval_joined
GROUP BY dataset
ORDER BY dataset;

.print ''
.print '--- Evaluation complete ---'
